import React from 'react';
import './Experience.css';

const Experience = () => {
  const experiences = [
    {
      company: "University of Nebraska Omaha (UNO)",
      location: "Omaha, NE, USA",
      duration: "July 2023 - Present",
      role: "Graduate Research Assistant",
      supervisor: "Supervisor: Dr. Pei-Chi Huang, Assistant Professor, Dept. of Computer Science, UNO",
      description: "Working Field: Digital Twin, DL based Networking Congestion Control, Cyber Physical System."
    },
    {
      company: "University of Nebraska Omaha (UNO)",
      location: "Omaha, NE, USA",
      duration: "Aug. 2022 - June 2023",
      role: "Graduate Research Assistant",
      supervisor: "Supervisor: Dr. Spyridon Mastorakis, Assistant Professor, Dept. of Computer Science, UNO",
      description: "Working Field: Networking Security and Privacy, Virtual Reality Privacy, ML for IoT’s Congestion Control."
    },
    {
      company: "Samsung R&D Institute Bangladesh",
      location: "Sylhet, Bangladesh",
      duration: "Dec. 2018 – Jul. 2022",
      role: "Software Engineer",
      description: "Working Field: Fetching, parsing, storing and showing the cloud data to the users; Communicating with IoT devices; Onboarding the IoT devices to the cloud; optimizing the Onboarding System."
    }
  ];

  return (
    <div className="experience-container">
      <h1>Work Experience</h1>
      <div className="experience-content">
        <div className="experience-companies">
          {experiences.map((exp, index) => (
            <div key={index} className="experience-company">
              <h2>{exp.company}</h2>
              <p>{exp.location}</p>
              <p>{exp.duration}</p>
            </div>
          ))}
        </div>
        <div className="experience-details">
          {experiences.map((exp, index) => (
            <div key={index} className="experience-detail">
              <h2>{exp.role}</h2>
              <p><strong>{exp.supervisor}</strong></p>
              <p>{exp.description}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Experience;
